	colour1 = "#ff5f00";
	colour2 = "#00ff7c";
	colour3 = "#dea7ff";
	fontString = "bold 12px Inter, sans-serif";
	enabled = true;
	shiftDown = false;
	undoDown = false;
	redoDown = false;
	ctrlDown = false;
	altDown = false;
	mouse0Down = false;
	mouse1Down = false;
	mouse2Down = false;
