		this.ctrlDown = e.ctrlKey;
		this.altDown = e.altKey;
		this.shiftDown = e.shiftKey;
		this.undoDown = e.ctrlKey && e.code === "KeyZ" && e.type === "keydown";
		this.redoDown = e.ctrlKey && e.code === "KeyY" && e.type === "keydown";
